import React, { useEffect, useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, Alert, Platform, StyleSheet, ActivityIndicator } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_KEY = 'authenticated';
const USERNAME_KEY = 'saved_username';
const PASSWORD_KEY = 'saved_password';

const rnBiometrics = new ReactNativeBiometrics();

const LoginScreen = ({ onLoginSuccess }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loadingBiometric, setLoadingBiometric] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);

  useEffect(() => {
    checkBiometricSupport();
  }, []);

  const checkBiometricSupport = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricAvailable(available);
      setBiometricType(biometryType);
    } catch (e) {
      setBiometricAvailable(false);
      setBiometricType(null);
    }
  };

  const handleBiometricLogin = async () => {
    try {
      setLoadingBiometric(true);
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: biometricType === ReactNativeBiometrics.Biometrics ? 'Authenticate' : 'Authenticate with biometrics',
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
      }
    } catch (e) {
      Alert.alert('Authentication Failed', 'Biometric authentication was cancelled or failed.');
    } finally {
      setLoadingBiometric(false);
    }
  };

  const handlePasswordLogin = async () => {
    if (!username || !password) {
      Alert.alert('Missing Fields', 'Please enter username and password.');
      return;
    }

    try {
      const savedUsername = await AsyncStorage.getItem(USERNAME_KEY);
      const savedPassword = await AsyncStorage.getItem(PASSWORD_KEY);

      if (savedUsername === null || savedPassword === null) {
        await AsyncStorage.setItem(USERNAME_KEY, username);
        await AsyncStorage.setItem(PASSWORD_KEY, password);
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
        return;
      }

      if (username === savedUsername && password === savedPassword) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
      } else {
        Alert.alert('Invalid Credentials', 'Username or password is incorrect.');
      }
    } catch (e) {
      Alert.alert('Error', 'Unable to complete login.');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      <TextInput
        style={styles.input}
        placeholder="Username"
        autoCapitalize="none"
        value={username}
        onChangeText={setUsername}
      />

      <TextInput
        style={styles.input}
        placeholder="Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />

      {biometricAvailable ? (
        <TouchableOpacity style={styles.button} onPress={handleBiometricLogin} disabled={loadingBiometric}>
          {loadingBiometric ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Use {Platform.OS === 'ios' ? 'Face ID / Touch ID' : 'Fingerprint'}</Text>}
        </TouchableOpacity>
      ) : null}

      <TouchableOpacity style={styles.button} onPress={handlePasswordLogin}>
        <Text style={styles.buttonText}>Login with Password</Text>
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = ({ onLogout }) => {
  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    onLogout();
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text>You are authenticated.</Text>
      <TouchableOpacity style={styles.button} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

export default function App() {
  const [authenticated, setAuthenticated] = useState(false);
  const [checkingAuth, setCheckingAuth] = useState(true);

  useEffect(() => {
    bootstrapAuth();
  }, []);

  const bootstrapAuth = async () => {
    try {
      const authFlag = await AsyncStorage.getItem(AUTH_KEY);
      setAuthenticated(authFlag === 'true');
    } catch (e) {
      setAuthenticated(false);
    } finally {
      setCheckingAuth(false);
    }
  };

  if (checkingAuth) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return authenticated ? (
    <HomeScreen onLogout={() => setAuthenticated(false)} />
  ) : (
    <LoginScreen onLoginSuccess={() => setAuthenticated(true)} />
  );
}

